extern unsigned char sscreen[SCREEN_WIDTH*SCREEN_HEIGHT*2];

#define SHIFTSTR 2
	
int chooseFile(char* path, char* initpath, char* title) {
		int j,i,li,s, refresh, shouldwait, t, cancelled=0, parent=0, validated=0, si=0;
		int touchedzone=0;
		char ext[5], dext[9];
		initTP();
		strcpy(path,initpath);
		char* p = strrchr(path,'/');
		if(p)	*(p+1)=0;
		dfileinfo* filenames[1024];
		int fileselected=0;
		while(!fileselected && !cancelled) {
			int numfiles = dirlist(path, filenames);
			refresh=1; li=-1; si=0;
//			if(!strcmp(filenames[0],"."))
//				si+=2;
			s=si; i=s;
			shouldwait=0;
			validated=0;
			while (!validated && !cancelled) {
				parent=0;
				if( refresh ) {
					int size=320*(6*ICON_HEIGHT)*2;
					memcpy(getScreen(),sscreen,size);
					clrBufBox(getScreen(),0,6*ICON_HEIGHT,320,240-6*ICON_HEIGHT);
					resetConsole(0);
					drwBufStr(getScreen(),160,4.5*ICON_HEIGHT,title,0,1);
					drwBufStr(getScreen(),20,5*ICON_HEIGHT+6,path,0,1);
					dispBufImgRGB(getScreen(),0,5*ICON_HEIGHT,ofoldimg,16,15,1);
					for (j = s; j < numfiles && j-s<MAX_ICONLGN-2; j++) {
						t = strlen(filenames[j]->filename);
						*ext=0;
						if(t>=4)
							strcpy(ext,filenames[j]->filename+t-4);
						*dext=0;
						if(t>=4)
							strcpy(dext,filenames[j]->filename+t-8);
						if(filenames[j]->isdir)
							dispBufImgRGB(getScreen(),20,(j-s+6)*ICON_HEIGHT+1,cfoldimg,16,15,1);
						else {
							if(	!strcmp(dext,".bmp.tns") || !strcmp(dext,".png.tns") || !strcmp(dext,".jpg.tns") || !strcmp(dext,".jpeg.tns") || !strcmp(dext,".dib.tns") ||
								!strcmp(dext,".BMP.tns") || !strcmp(dext,".PNG.tns") || !strcmp(dext,".JPG.tns") || !strcmp(dext,".JPEG.tns") || !strcmp(dext,".DIB.tns"))
								dispBufImgRGB(getScreen(),22,(j-s+6)*ICON_HEIGHT+1,bmpimg,12,13,1);
							else
								dispBufImgRGB(getScreen(),22,(j-s+6)*ICON_HEIGHT+1,fileimg,12,13,1);
					  	}
						drwBufStr(getScreen(),40,ICON_HEIGHT*(j-s+6)+2+SHIFTSTR,filenames[j]->filename,0,0);
					}
					setCurColorRGB(0,0,0);
					drwBufBox(getScreen(),38,ICON_HEIGHT*(i-s+6),SCREEN_WIDTH-1,ICON_HEIGHT*(i-s+7)-1);

					if(s>si) putBufChar(getScreen(),0,ICON_HEIGHT*6+1,23, 0);
					if(s+MAX_ICONLGN-1<numfiles) putBufChar(getScreen(),0,(MAX_ICONLGN-1+4)*ICON_HEIGHT+5,24, 0);
					refresh=0;					
					wait(250);
				}
				readTP();
				touchedzone=getTouchedZone5();
				if( numfiles-si>0 ) {
					if (isKeyPressed(KEY_NSPIRE_UP) || isKeyPressed(KEY_NSPIRE_8) || touchedzone==8) {
						i--;
						if (i < si) i = numfiles-1;
					}
					if (isKeyPressed(KEY_NSPIRE_DOWN) || isKeyPressed(KEY_NSPIRE_2) || touchedzone==2) {
						i++;
						if (i >= numfiles) i = si;
					}
					if (i!=li) {
						while(i<s)
						{	s-=MAX_ICONLGN-2;
						 	refresh=1;
						  	if( s<si ) s=si;
						}
						while(i-s>=MAX_ICONLGN-2)
						{	s+=MAX_ICONLGN-2;
							refresh=1;
							if(s>numfiles-MAX_ICONLGN+1) s=numfiles-MAX_ICONLGN+2;
						}
						if(!refresh)
						{ 	setCurColorRGB(0xFF,0xFF,0xFF);
							if(li>=0) drwBufBox(getScreen(),38,ICON_HEIGHT*(li-s+6),SCREEN_WIDTH-1,ICON_HEIGHT*(li-s+7)-1);
							setCurColorRGB(0,0,0);
							drwBufBox(getScreen(),38,ICON_HEIGHT*(i-s+6),SCREEN_WIDTH-1,ICON_HEIGHT*(i-s+7)-1);
							wait(250);
						}
						li=i;
					}
				}
				if(isKeyPressed(KEY_NSPIRE_ESC))
					cancelled=1;
				if((isKeyPressed(KEY_NSPIRE_LEFT) && !isKeyPressed(KEY_NSPIRE_UP) && !isKeyPressed(KEY_NSPIRE_DOWN)) || isKeyPressed(KEY_NSPIRE_4) || touchedzone==4)
				{	parent=1;	validated=1; }
				if((numfiles-si>0 && (isKeyPressed(KEY_NSPIRE_ENTER) || isKeyPressed(KEY_NSPIRE_RET) || isKeyPressed(KEY_NSPIRE_CLICK) || isKeyPressed(KEY_NSPIRE_5) || isKeyPressed(KEY_NSPIRE_6) || (isKeyPressed(KEY_NSPIRE_RIGHT) && !isKeyPressed(KEY_NSPIRE_UP) && !isKeyPressed(KEY_NSPIRE_DOWN)))) || touchedzone==6)
					validated=1;
				wait(10);
			}
			if(!cancelled)
			{	char* selected = filenames[i]->filename;
				if(strcmp(selected,".") || parent)
				{	if(!strcmp(selected,"..") || parent)
					{	t=strlen(path);
						if(t>1)
						{	path[t-1]=0;
							p = strrchr(path,'/');
							if(p)	*(p+1)=0;
						}
						shouldwait=1;
					}
					else
					{	strcat(path,selected);
						if(!filenames[i]->isdir)
							fileselected=1;
						else {
							strcat(path,"/");
							shouldwait=1;
						}
					}
					if(shouldwait) { wait(250); shouldwait=0; }
				}
			}
			for(i=0;i<numfiles;i++)
				free(filenames[i]);
		}
		endTP();
		return !cancelled;
}

int prevFile(char* path, char* initpath) {
	int i;
	char* tmppath=malloc(strlen(initpath)+1);
	strcpy(tmppath,initpath);
	strcpy(path,tmppath);
	char* p = strrchr(path,'/');
	if(p)
		*(p+1)=0;
	p = strrchr(tmppath,'/');
	p++;
	dfileinfo* filenames[1024];
	int numfiles = dirlist(path, filenames);
	for(i=numfiles-1;i>=0;i--)
		if(!filenames[i]->isdir)
			if(strcmp(filenames[i]->filename,p)<0)
				break;
	free(tmppath);
	if(i>=0) {
		strcat(path,filenames[i]->filename);
		return 1;
	}
	return 0;
}

int nextFile(char* path, char* initpath) {
	int i;
	char* tmppath=malloc(strlen(initpath)+1);
	strcpy(tmppath,initpath);
	strcpy(path,tmppath);
	char* p = strrchr(path,'/');
	if(p)
		*(p+1)=0;
	p = strrchr(tmppath,'/');
	p++;
	dfileinfo* filenames[1024];
	int numfiles = dirlist(path, filenames);
	for(i=0;i<numfiles;i++)
		if(!filenames[i]->isdir)
			if(strcmp(filenames[i]->filename,p)>0)
				break;
	free(tmppath);
	if(i<numfiles) {
		strcat(path,filenames[i]->filename);
		return 1;
	}
	return 0;
}